using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions; // Required for formatting

public class ReviewsController : Controller
{
    private readonly ApplicationDbContext _context; // Your DbContext

    public ReviewsController(ApplicationDbContext context)
    {
        _context = context;
    }

    [HttpGet]
    public IActionResult ProductReviews(int productId)
    {
        // Fetch reviews for the given productId from the database
        var reviews = _context.Reviews
                              .Where(r => r.ProductId == productId)
                              .OrderByDescending(r => r.ReviewDate)
                              .ToList();

        // Process reviews for display, applying basic formatting
        var formattedReviews = reviews.Select(r => new ReviewViewModel
        {
            ReviewId = r.ReviewId,
            UserName = r.UserName,
            Rating = r.Rating,
            Comment = FormatReviewText(r.Comment), // Apply formatting
            ReviewDate = r.ReviewDate
        }).ToList();

        // Pass the formatted reviews to the view
        ViewBag.ProductName = _context.Products.Find(productId)?.Name ?? "Unknown Product"; // Example: Fetch product name
        return View(formattedReviews);
    }

    // This method simulates applying basic formatting
    // In a real application, you might use a more robust markdown parser or sanitize HTML
    private string FormatReviewText(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return string.Empty;
        }

        // Basic formatting: **bold** to <strong>bold</strong>
        text = Regex.Replace(text, @"\*\*(.*?)\*\*", "<strong>$1</strong>");

        // Basic formatting: *italic* to <em>italic</em>
        text = Regex.Replace(text, @"\*(.*?)\*", "<em>$1</em>");

        // Consider additional security: Sanitize potential HTML if not using a dedicated markdown parser
        // For simple formatting like this, direct replacement is often fine if input is controlled.
        // If users can submit arbitrary HTML, use an HTML sanitizer library like AngleSharp.
        
        return text;
    }
}

